using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

build.VisitAllChildren<Error>(e =>
{
    var project = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((project, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? "", e.Subcategory ?? ""));
});

build.VisitAllChildren<Warning>(w =>
{
    var project = "";
    var node = w.Parent;
    while (node != null)
    {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    warnings.Add((project, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"[{e.Project}] {e.File}({e.Line},{e.Col}): error {e.Code}: {e.Message}");
}

Console.WriteLine();
Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var w in warnings)
{
    Console.WriteLine($"[{w.Project}] {w.File}({w.Line},{w.Col}): warning {w.Code}: {w.Message}");
}

// Show project dependency graph
Console.WriteLine();
Console.WriteLine("=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(p =>
{
    var targets = p.TargetFramework ?? "";
    Console.WriteLine($"Project: {p.Name} (TF: {targets}) Succeeded: {p.Succeeded}");
});

// Show source file contents if embedded
Console.WriteLine();
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
var archive = build.SourceFilesArchive;
if (archive != null)
{
    foreach (var entry in archive.Files)
    {
        if (entry.FullPath.EndsWith(".cs") && !entry.FullPath.Contains("/obj/"))
        {
            Console.WriteLine($"\n--- {entry.FullPath} ---");
            using var sr = new StreamReader(entry.Open());
            Console.WriteLine(sr.ReadToEnd());
        }
    }
}

