cat > /tmp/binlog-parser/Program.cs << 'CSHARP_EOF'
using System.IO.Compression;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

var errors = new List<(string Project, string Target, string File, int Line, int Col, string Code, string Message)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

build.VisitAllChildren<Error>(e =>
{
    var project = "";
    var target = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Target t && target == "") target = t.Name;
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((project, target, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? ""));
});

build.VisitAllChildren<Warning>(w =>
{
    var project = "";
    var node = w.Parent;
    while (node != null)
    {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    warnings.Add((project, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"[{e.Project}] ({e.Target}) {e.File}({e.Line},{e.Col}): error {e.Code}: {e.Message}");
}

Console.WriteLine();
Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var w in warnings)
{
    Console.WriteLine($"[{w.Project}] {w.File}({w.Line},{w.Col}): warning {w.Code}: {w.Message}");
}

// Show project dependency graph
Console.WriteLine();
Console.WriteLine("=== PROJECT BUILD ORDER ===");
build.VisitAllChildren<Project>(p =>
{
    var tf = p.TargetFramework ?? "";
    Console.WriteLine($"  Project: {p.Name} (TF: {tf})");
});

// Decode embedded sources from the SourceFilesArchive (raw zip bytes)
Console.WriteLine();
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
var archiveBytes = build.SourceFilesArchive;
if (archiveBytes != null && archiveBytes.Length > 0)
{
    using var ms = new MemoryStream(archiveBytes);
    using var zip = new ZipArchive(ms, ZipArchiveMode.Read);
    foreach (var entry in zip.Entries)
    {
        if (entry.FullName.EndsWith(".cs") && !entry.FullName.Contains("/obj/"))
        {
            Console.WriteLine($"\n--- {entry.FullName} ---");
            using var sr = new StreamReader(entry.Open());
            Console.WriteLine(sr.ReadToEnd());
        }
    }
}
else
{
    Console.WriteLine("No embedded source archive found.");
}
CSHARP_EOF
