    {
        var ext = Path.GetExtension(entry.FullName);
        if (ext is ".cs" or ".csproj" or ".sln" or ".json" or ".targets" or ".props")
        {
            // Skip SDK/obj files
            if (entry.FullName.Contains("/usr/share/dotnet/")) continue;
            if (entry.FullName.Contains("/obj/") && entry.FullName.EndsWith(".json")) continue;
            if (entry.FullName.Contains("/obj/") && entry.FullName.Contains("AssemblyInfo")) continue;
            if (entry.FullName.Contains("/obj/") && entry.FullName.Contains("AssemblyAttributes")) continue;
            if (entry.FullName.Contains("/obj/") && entry.FullName.EndsWith(".targets")) continue;

            Console.WriteLine($"\n--- {entry.FullName} ---");
            using var sr = new StreamReader(entry.Open());
            Console.WriteLine(sr.ReadToEnd());
        }
    }
}

