        || m.Text.Contains("failed") || m.Text.Contains("not build")))
    {
        var project = "";
        var node = m.Parent;
        while (node != null)
        {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"[{project}] {m.Text}");
    }
});

